class Solution {
public:
    int numberOfWays(int n, int x, int y) {
        const int MOD = 1e9 + 7;
        vector<vector<long long>> dp(n + 1, vector<long long>(x + 1));
        dp[0][0] = 1;

        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= min(i, x); ++j) {
                dp[i][j] = (dp[i - 1][j - 1] * j + dp[i - 1][j] * (x - j + 1)) % MOD;
            }
        }

        long long res = 0;
        for (int j = 1; j <= x; ++j) {
            res = (res + dp[n][j] * pow(y, j, MOD)) % MOD;
        }
        return res;
    }
};
